solution.approach:
From (1,1) to (N,M) we need (N‑1) vertical moves and (M‑1) horizontal moves. A diagonal move reduces both a vertical and a horizontal requirement by one, so we can use at most d = min(N‑1, M‑1) diagonal steps. If a diagonal is cheaper than doing the same displacement with two orthogonal moves (i.e., Y ≤ 2·X), we use as many diagonals as possible; otherwise we never use a diagonal because two orthogonal moves are cheaper. The remaining displacement after using d diagonals is |N‑M| orthogonal steps. The answer is therefore:
```
if (Y <= 2*X) {
    d = min(N-1, M-1);
    cost = d*Y + abs(N-M)*X;
} else {
    cost = (N+M-2)*X;
}
```
The computation is O(1) per test case, so total time is O(T) and only O(1) extra memory is needed.

code.C:
#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N,M,X,Y; scanf("%lld %lld %lld %lld", &N, &M, &X, &Y);
        long long vertical = N-1, horizontal = M-1;
        long long cost;
        if (Y <= 2*X){
            long long d = vertical < horizontal ? vertical : horizontal;
            cost = d*Y + llabs(N-M)*X;
        } else {
            cost = (vertical + horizontal) * X;
        }
        printf("%lld\n", cost);
    }
    return 0;
}

