    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for(int t=0; t<T; t++){
            StringTokenizer st = new StringTokenizer(br.readLine());
            long N = Long.parseLong(st.nextToken());
            long M = Long.parseLong(st.nextToken());
            long X = Long.parseLong(st.nextToken());
            long Y = Long.parseLong(st.nextToken());
            long vertical = N-1, horizontal = M-1;
            long ans;
            if(Y <= 2*X){
                long d = Math.min(vertical, horizontal);
                ans = d*Y + Math.abs(N-M)*X;
            }else{
                ans = (vertical + horizontal) * X;
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); X = int(next(it)); Y = int(next(it))
        vertical = N-1
        horizontal = M-1
        if Y <= 2*X:
            d = vertical if vertical < horizontal else horizontal
            cost = d*Y + abs(N-M)*X
        else:
            cost = (vertical + horizontal) * X
        out_lines.append(str(cost))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

